import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import MainLayout from './components/Layout/MainLayout';
import Dashboard from './pages/Dashboard';
import MyTasks from './pages/MyTasks';
import Team from './pages/Team';
import Profile from './pages/Profile';
import SignInPage from './pages/SignInPage';
import SignUpPage from './pages/SignUpPage';
import './styles/App.css';

// Mock data for development
const mockUsers = [
  { id: 1, name: 'Wayne Travis', email: 'wayne@example.com', role: 'project_manager' },
  { id: 2, name: 'Sarah Johnson', email: 'sarah@example.com', role: 'team_lead' },
  { id: 3, name: 'Mike Chen', email: 'mike@example.com', role: 'developer' },
  { id: 4, name: 'Emily Rodriguez', email: 'emily@example.com', role: 'designer' }
];

const mockProjects = [
  { 
    id: 1, 
    name: 'Website Redesign', 
    description: 'Complete redesign of company website with modern UI/UX',
    due_date: '2023-12-15',
    manager_id: 1,
    progress: 65,
    status: 'In Progress',
    priority: 'high',
    created_at: '2023-09-01',
    updated_at: '2023-09-25'
  },
  { 
    id: 2, 
    name: 'Mobile App Development', 
    description: 'Build cross-platform mobile application',
    due_date: '2024-01-30',
    manager_id: 2,
    progress: 30,
    status: 'In Progress',
    priority: 'high',
    created_at: '2023-09-15',
    updated_at: '2023-09-26'
  },
  { 
    id: 3, 
    name: 'Marketing Campaign', 
    description: 'Q4 marketing campaign launch',
    due_date: '2023-11-15',
    manager_id: 1,
    progress: 15,
    status: 'Not Started',
    priority: 'medium',
    created_at: '2023-09-20',
    updated_at: '2023-09-20'
  }
];

const mockTasks = [
  {
    id: 1,
    title: 'Design Homepage',
    description: 'Create new homepage layout with improved UX',
    project_id: 1,
    assignee_id: 3,
    status: 'In Progress',
    priority: 'high',
    due_date: '2023-10-15',
    created_at: '2023-09-20',
    updated_at: '2023-09-25'
  },
  {
    id: 2,
    title: 'Implement Authentication',
    description: 'Set up user authentication system',
    project_id: 2,
    assignee_id: 3,
    status: 'Completed',
    priority: 'high',
    due_date: '2023-10-05',
    created_at: '2023-09-15',
    updated_at: '2023-09-24'
  },
  {
    id: 3,
    title: 'Create Marketing Assets',
    description: 'Design social media and email marketing assets',
    project_id: 3,
    assignee_id: 4,
    status: 'Not Started',
    priority: 'medium',
    due_date: '2023-10-20',
    created_at: '2023-09-22',
    updated_at: '2023-09-22'
  }
];

// Protected Route Component
const ProtectedRoute = ({ children }) => {
  const { currentUser } = useAuth();

  if (!currentUser) {
    return <Navigate to="/signin" replace />;
  }

  return (
    <MainLayout>
      {children}
    </MainLayout>
  );
};

// App Routes Component
const AppRoutes = () => {
  return (
    <Routes>
      <Route path="/signin" element={!useAuth().currentUser ? <SignInPage /> : <Navigate to="/dashboard" replace />} />
      <Route path="/signup" element={!useAuth().currentUser ? <SignUpPage /> : <Navigate to="/dashboard" replace />} />

      <Route path="/" element={<Navigate to="/dashboard" replace />} />

      <Route path="/dashboard" element={
        <ProtectedRoute>
          <Dashboard projects={mockProjects} tasks={mockTasks} users={mockUsers} />
        </ProtectedRoute>
      } />

      <Route path="/my-tasks" element={
        <ProtectedRoute>
          <MyTasks tasks={mockTasks} projects={mockProjects} users={mockUsers} />
        </ProtectedRoute>
      } />

      <Route path="/team" element={
        <ProtectedRoute>
          <Team users={mockUsers} />
        </ProtectedRoute>
      } />

      <Route path="/profile" element={
        <ProtectedRoute>
          <Profile users={mockUsers} />
        </ProtectedRoute>
      } />

      <Route path="*" element={<Navigate to="/dashboard" replace />} />
    </Routes>
  );
};

function App() {
  return (
    <Router>
      <AuthProvider>
        <div className="app">
          <AppRoutes />
        </div>
      </AuthProvider>
    </Router>
  );
}

export default App;
